#include <iostream>
#include <vector>
#include <random>
#include <algorithm>

// Function to perform bubble sort on a vector
std::vector<long long> bubble_sort(const std::vector<long long>& arr) {
    std::vector<long long> sorted_arr = arr;
    long long n = sorted_arr.size();
    for (long long i = 0; i < n; ++i) {
        for (long long j = 0; j < n - i - 1; ++j) {
            if (sorted_arr[j] > sorted_arr[j + 1]) {
                std::swap(sorted_arr[j], sorted_arr[j + 1]);
            }
        }
    }
    return sorted_arr;
}

int main() {
    // Initialize random number generator with seed 42
    std::random_device rd;
    std::mt19937 gen(42);
    std::uniform_int_distribution<long long> dis(0, 100000);

    // Generate 10,000 random integers between 0 and 100,000
    std::vector<long long> data;
    data.reserve(10000);
    for (int i = 0; i < 10000; ++i) {
        data.push_back(dis(gen));
    }

    // Perform bubble sort on the generated data
    std::vector<long long> result = bubble_sort(data);

    // Print the results
    std::cout << "Sorted " << result.size() << " elements" << std::endl;
    std::cout << "First 5: ";
    for (int i = 0; i < 5; ++i) {
        std::cout << result[i] << " ";
    }
    std::cout << std::endl;
    std::cout << "Last 5: ";
    for (int i = result.size() - 5; i < result.size(); ++i) {
        std::cout << result[i] << " ";
    }
    std::cout << std::endl;

    return 0;
}

