#include <iostream>
#include <vector>
#include <random>
#include <numeric>
#include <algorithm>

std::vector<long long> sieve_of_eratosthenes(long long limit) {
    std::vector<bool> is_prime(limit + 1, true);
    is_prime[0] = is_prime[1] = false;

    for (long long i = 2; i * i <= limit; ++i) {
        if (is_prime[i]) {
            for (long long j = i * i; j <= limit; j += i) {
                is_prime[j] = false;
            }
        }
    }

    std::vector<long long> primes;
    for (long long num = 2; num <= limit; ++num) {
        if (is_prime[num]) {
            primes.push_back(num);
        }
    }

    return primes;
}

int main() {
    const long long LIMIT = 5'000'000;
    std::vector<long long> primes = sieve_of_eratosthenes(LIMIT);

    std::cout << "Found " << primes.size() << " primes up to " << LIMIT << "\n";
    std::cout << "Largest prime: " << primes.back() << "\n";
    std::cout << "First 10 primes: ";
    for (size_t i = 0; i < 10 && i < primes.size(); ++i) {
        std::cout << primes[i] << " ";
    }
    std::cout << "\n";

    return 0;
}

