#include <omp.h>
#include <iostream>
#include <vector>
#include <random>

// Create a matrix filled with random floats
std::vector<std::vector<double>> create_matrix(int rows, int cols, int seed) {
    std::mt19937 gen(seed);
    std::uniform_real_distribution<double> dis(0.0, 1.0);
    std::vector<std::vector<double>> matrix(rows, std::vector<double>(cols));
    #pragma omp parallel for
    for (int i = 0; i < rows; ++i) {
        for (int j = 0; j < cols; ++j) {
            matrix[i][j] = dis(gen);
        }
    }
    return matrix;
}

// Multiply two matrices using the standard O(n^3) algorithm
std::vector<std::vector<double>> matrix_multiply(const std::vector<std::vector<double>>& A, const std::vector<std::vector<double>>& B) {
    int rows_A = A.size();
    int cols_A = A[0].size();
    int cols_B = B[0].size();
    std::vector<std::vector<double>> C(rows_A, std::vector<double>(cols_B, 0.0));
    #pragma omp parallel for
    for (int i = 0; i < rows_A; ++i) {
        for (int j = 0; j < cols_B; ++j) {
            double sum = 0.0;
            #pragma omp parallel for reduction(+:sum)
            for (int k = 0; k < cols_A; ++k) {
                sum += A[i][k] * B[k][j];
            }
            #pragma omp atomic
            C[i][j] = sum;
        }
    }
    return C;
}

int main() {
    omp_set_num_threads(omp_get_max_threads());
    const int SIZE = 200;
    auto A = create_matrix(SIZE, SIZE, 42);
    auto B = create_matrix(SIZE, SIZE, 123);

    auto C = matrix_multiply(A, B);
    std::cout << "Multiplied " << SIZE << "x" << SIZE << " matrices" << std::endl;
    std::cout << "Result[0][0] = " << C[0][0] << std::endl;
    std::cout << "Result[0][1] = " << C[0][1] << std::endl;
    return 0;
}
